// Recebe o JSON original do webhook em $item(0).$node["Webhook Entrada"].json
// e gera um HTML dark com KPIs + gráfico (heurística simples) + tabela dinâmica.

const original = $item(0).$node["Webhook Entrada"].json || {};
const rows = Array.isArray(original.data) ? original.data : [];
const title = "Visualização de Dados (Fallback)";
const dataJson = JSON.stringify({ data: rows });

function escapeHtml(s){ return String(s).replace(/[&<>"']/g, m => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m])); }

// Heurística mínima: 1 categoria + 1 métrica ⇒ barras/pizza; senão tabela.
let labelKey = null, valueKey = null;
if (rows.length) {
  const sample = rows[0];
  const keys = Object.keys(sample);
  const numericKeys = keys.filter(k => typeof sample[k] === 'number' && isFinite(sample[k]));
  const catKeys = keys.filter(k => typeof sample[k] !== 'number');

  if (numericKeys.length >= 1 && catKeys.length >= 1) {
    valueKey = numericKeys[0];
    labelKey = catKeys[0];
  }
}

const html = `
<html lang="pt-br">
<head>
  <meta charset="utf-8" />
  <title>${escapeHtml(title)}</title>
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <script src="https://cdn.jsdelivr.net/npm/chart.js"></script>
  <style>
    :root { --bg:#0f111a; --card:#1a1c2b; --text:#e5e7ef; --muted:#a0a3b7; --line:#2a2d3e; }
    *{ box-sizing:border-box }
    body{ margin:0; background:var(--bg); color:var(--text); font-family:Inter,system-ui,Arial,sans-serif; }
    header{ padding:20px 24px 8px; border-bottom:1px solid #222538; }
    h1{ margin:0; font-size:20px; font-weight:700 }
    .sub{ margin:6px 0 0; color:var(--muted); font-size:13px }
    main{ padding:20px 24px; display:flex; flex-direction:column; gap:20px }
    .row{ display:flex; flex-wrap:wrap; gap:16px }
    .card{ background:var(--card); border-radius:16px; box-shadow:0 2px 12px rgb(0 0 0 / .4) }
    .kpi{ padding:16px 20px; min-width:180px; flex:1 1 180px }
    .kpi h3{ margin:0 0 6px; font-size:12px; color:#9ca3ff; letter-spacing:.3px }
    .kpi .v{ font-size:18px; font-weight:700 }
    .chart{ padding:16px 20px; height:520px; }
    .btns{ display:flex; gap:12px; padding:0 20px 16px }
    button{ background:#2e2f48; color:var(--text); border:none; border-radius:14px; padding:10px 16px; font-weight:600; cursor:pointer }
    button:hover{ background:#44475a }
    .tblwrap{ padding:16px 20px; overflow:auto }
    table{ width:100%; border-collapse:collapse; font-size:14px }
    th,td{ padding:10px 12px; border-bottom:1px solid var(--line); text-align:left; white-space:nowrap }
    th{ position:sticky; top:0; background:var(--card); cursor:pointer; user-select:none }
    th.sort-asc::after{ content:" ▲"; font-size:12px }
    th.sort-desc::after{ content:" ▼"; font-size:12px }
    .toolbar{ display:flex; gap:12px; padding:0 20px 12px }
    .toolbar input{ background:#2e2f48; color:var(--text); border:none; border-radius:10px; padding:8px 12px; min-width:220px }
    .muted{ color:var(--muted); font-size:12px; padding:0 4px 12px 20px }
  </style>
</head>
<body>
  <header>
    <h1>${escapeHtml(title)}</h1>
    <p class="sub">Fallback automático: gera visualização mesmo sem o agente.</p>
  </header>
  <main>
    <section class="row">
      <div class="card kpi"><h3>Registros</h3><div class="v" id="k-rows">-</div></div>
      <div class="card kpi"><h3>Colunas</h3><div class="v" id="k-cols">-</div></div>
      <div class="card kpi"><h3>Métrica (soma)</h3><div class="v" id="k-sum">-</div></div>
      <div class="card kpi"><h3>Métrica (média)</h3><div class="v" id="k-avg">-</div></div>
    </section>

    <section class="card chart" id="chartSection" style="${labelKey && valueKey ? '' : 'display:none'}">
      <canvas id="chart"></canvas>
      <div class="btns"><button id="dlpng" type="button">Baixar PNG</button></div>
      <p class="muted" id="reason"></p>
    </section>

    <section class="card">
      <div class="toolbar">
        <input id="q" placeholder="Buscar..." />
      </div>
      <div class="tblwrap">
        <table id="tbl"><thead></thead><tbody></tbody></table>
      </div>
    </section>
  </main>

  <script>window.__DATA__ = ${dataJson};</script>
  <script>
    const raw = window.__DATA__ || { data: [] };
    const rows = Array.isArray(raw.data) ? raw.data : [];
    const fmt = n => (typeof n === 'number' && isFinite(n)) ? n.toLocaleString('pt-BR') : '-';

    // KPIs
    const cols = rows.length ? Object.keys(rows[0]) : [];
    const numKeys = rows.length ? Object.keys(rows[0]).filter(k => typeof rows[0][k] === 'number' && isFinite(rows[0][k])) : [];
    const firstMetric = numKeys[0];
    let sum = 0, avg = 0;
    if (rows.length && firstMetric) {
      const vals = rows.map(r => Number(r[firstMetric]) || 0);
      sum = vals.reduce((a,b)=>a+b,0);
      avg = vals.length ? sum/vals.length : 0;
    }
    document.getElementById('k-rows').textContent = fmt(rows.length);
    document.getElementById('k-cols').textContent = fmt(cols.length);
    document.getElementById('k-sum').textContent  = firstMetric ? fmt(sum) : '-';
    document.getElementById('k-avg').textContent  = firstMetric ? fmt(avg) : '-';

    // Tabela
    const thead = document.querySelector('#tbl thead');
    const tbody = document.querySelector('#tbl tbody');
    function renderHead(keys){
      const tr = document.createElement('tr');
      keys.forEach(k=>{
        const th = document.createElement('th'); th.textContent = k;
        th.onclick = ()=> sortBy(k);
        tr.appendChild(th);
      });
      thead.innerHTML=''; thead.appendChild(tr);
    }
    let current = rows.slice();
    function renderBody(list){
      const keys = cols;
      tbody.innerHTML='';
      list.forEach(r=>{
        const tr = document.createElement('tr');
        keys.forEach(k=>{
          const td = document.createElement('td');
          let v = r[k];
          if (k.match(/cpf|cnpj|documento/i) && typeof v === 'string' && v.length >= 5) {
            v = v.slice(0,3) + '***' + v.slice(-2);
          }
          if (typeof v === 'number' && isFinite(v)) td.textContent = v.toLocaleString('pt-BR'); else td.textContent = v ?? '';
          tr.appendChild(td);
        });
        tbody.appendChild(tr);
      });
    }
    let sortState = { key:null, dir:1 };
    function sortBy(k){
      const keys = cols;
      const ths = thead.querySelectorAll('th'); ths.forEach(th=>th.classList.remove('sort-asc','sort-desc'));
      if (sortState.key === k) sortState.dir *= -1; else { sortState.key = k; sortState.dir = 1; }
      current.sort((a,b)=>{
        const va = a[k], vb = b[k];
        if (typeof va === 'number' && typeof vb === 'number') return (va - vb) * sortState.dir;
        return String(va ?? '').localeCompare(String(vb ?? ''), 'pt-BR') * sortState.dir;
      });
      const idx = keys.indexOf(k);
      if (idx >= 0) ths[idx].classList.add(sortState.dir>0 ? 'sort-asc' : 'sort-desc');
      renderBody(current);
    }
    renderHead(cols);
    renderBody(current);

    // Busca
    const q = document.getElementById('q');
    q.addEventListener('input', ()=>{
      const s = q.value.toLowerCase();
      current = rows.filter(r => cols.some(k => String(r[k] ?? '').toLowerCase().includes(s)));
      renderBody(current);
    });

    // Gráfico simples (se labelKey/valueKey existirem)
    ${labelKey && valueKey ? `
      const reason = "Comparativo 1×1: ${labelKey} × ${valueKey}";
      document.getElementById('reason').textContent = reason;
      const ctx = document.getElementById('chart').getContext('2d');
      const labels = rows.map(r => String(r['${labelKey}']));
      const data = rows.map(r => Number(r['${valueKey}']) || 0);
      const chart = new Chart(ctx, {
        type: labels.length > 15 ? 'bar' : (labels.length <= 8 ? 'pie' : 'bar'),
        data: {
          labels,
          datasets: [{ label: '${valueKey}', data }]
        },
        options: {
          responsive: true,
          plugins: { legend: { position: 'top' }, title: { display: true, text: '${valueKey}' } },
          scales: { y: { beginAtZero: true } }
        }
      });
      document.getElementById('dlpng').onclick = () => {
        const a = document.createElement('a');
        a.href = chart.toBase64Image(); a.download = 'grafico.png'; a.click();
      };
    ` : `
      // Sem par (categoria, métrica) claro: gráfico oculto, apenas tabela/KPIs
    `}
  </script>
</body>
</html>
`;

return [{ json: { html, fromFallback: true } }];
